356	    fn compute_cookie(&self, addr: &SocketAddr, offset: Option<isize>) -> u32 {
357	        let timestamp = (self.start_time.elapsed().as_secs() / 60) + offset.unwrap_or(0) as u64; // secret changes every one minute
358	        let host = addr.ip();
359	        let port = addr.port();
360	        let salt: &str = &(*SALT);
361	        u32::from_be_bytes(
362	            Sha256::digest(format!("{salt}:{host}:{port}:{timestamp}").as_bytes())[..4]
363	                .try_into()
364	                .unwrap(),
365	        )
366	    }
