376	    pub(crate) async fn listen_on_handshake(
377	        &self,
378	        addr: SocketAddr,
379	        hs: &HandShakeInfo,
380	    ) -> Result<()> {
381	        if !self.status().is_alive() {
382	            return Err(Error::new(ErrorKind::ConnectionRefused, "socket closed"));
383	        }
384	
385	        if hs.connection_type == 1 {
386	            // Regular connection, respond to handshake
387	            let mut hs_response = hs.clone();
388	            let dest_socket_id = hs_response.socket_id;
389	            hs_response.syn_cookie = self.compute_cookie(&addr, None);
390	            let hs_packet = UdtControlPacket::new_handshake(hs_response, dest_socket_id);
391	            self.send_to(&addr, hs_packet.into()).await?;
392	            return Ok(());
393	        }
394	
395	        if hs.connection_type != -1 {
396	            return Err(Error::new(
397	                ErrorKind::InvalidData,
398	                format!("invalid connection_type: {}", hs.connection_type),
399	            ));
400	        }
401	
402	        // Validate client response
403	        let syn_cookie = hs.syn_cookie;
404	        if syn_cookie != self.compute_cookie(&addr, None)
405	            && syn_cookie != self.compute_cookie(&addr, Some(-1))
406	        {
407	            // Invalid cookie;
408	            return Err(Error::new(ErrorKind::PermissionDenied, "invalid cookie"));
409	        }
410	
411	        let dest_socket_id = hs.socket_id;
412	        let udt_version = self.configuration.read().unwrap().udt_version();
413	        if hs.udt_version != udt_version || hs.socket_type != self.socket_type {
414	            // Reject request
415	            let mut hs_response = hs.clone();
416	            hs_response.connection_type = 1002; // Error codes defined in C++ implementation
417	            let hs_packet = UdtControlPacket::new_handshake(hs_response, dest_socket_id);
418	            self.send_to(&addr, hs_packet.into()).await?;
419	            return Err(Error::new(
420	                ErrorKind::ConnectionRefused,
421	                "configuration mismatch",
422	            ));
423	        }
424	
425	        Udt::get()
426	            .write()
427	            .await
428	            .new_connection(self, addr, hs)
429	            .await?;
430	        // Send handshake packet in case of errors on connection?
431	
432	        Ok(())
433	    }
