435	    pub(crate) async fn process_packet(&self, packet: UdtPacket) -> Result<()> {
436	        match packet {
437	            UdtPacket::Control(ctrl) => self.process_ctrl(ctrl).await,
438	            UdtPacket::Data(data) => self.process_data(data).await,
439	        }
440	    }
441	
442	    async fn process_ctrl(&self, packet: UdtControlPacket) -> Result<()> {
443	        {
444	            let mut state = self.state();
445	            state.exp_count = 1;
446	            state.last_rsp_time = Instant::now();
447	        }
448	
449	        match packet.packet_type {
450	            ControlPacketType::Handshake(hs) => {
451	                if self.status() != UdtStatus::Connecting {
452	                    return Err(Error::new(
453	                        ErrorKind::InvalidData,
454	                        format!(
455	                            "unexpected handshake for socket with status {:?}",
456	                            self.status
457	                        ),
458	                    ));
459	                }
460	
461	                // TODO: handle rendezvous mode
462	                if hs.connection_type > 0 {
463	                    let mut hs = hs.clone();
464	                    hs.connection_type = -1;
465	                    hs.socket_id = self.socket_id;
466	                    let hs_packet = UdtControlPacket::new_handshake(hs, 0);
467	                    self.send_packet(hs_packet.into()).await?;
468	                } else {
469	                    // post connect
470	                    let mut configuration = self.configuration.write().unwrap();
471	                    configuration.mss = hs.max_packet_size;
472	                    configuration.flight_flag_size = hs.max_window_size;
473	                    let mut state = self.state();
474	                    state.last_sent_ack = hs.initial_seq_number;
475	                    state.last_ack2_received = hs.initial_seq_number;
476	                    state.curr_rcv_seq_number = hs.initial_seq_number - 1;
477	                    *self.peer_socket_id.lock().unwrap() = Some(hs.socket_id);
478	
479	                    {
480	                        let mut rate_control = self.rate_control.write().unwrap();
481	                        rate_control.init(
482	                            configuration.mss,
483	                            &self.flow.read().unwrap(),
484	                            state.curr_snd_seq_number,
485	                        )
486	                    }
487	
488	                    *self.status.lock().unwrap() = UdtStatus::Connected;
489	                    self.connect_notify.notify_waiters();
490	                }
491	            }
492	            ControlPacketType::KeepAlive => (),
493	            ControlPacketType::Ack(ref ack) => {
494	                match &ack.info {
495	                    None => {
496	                        let mut state = self.state();
497	                        let seq = ack.next_seq_number;
498	                        let nb_acked = seq - state.last_ack_received;
499	                        if nb_acked >= 0 {
500	                            state.last_ack_received = seq;
501	                            self.flow.write().unwrap().flow_window_size -= (nb_acked) as u32;
502	                        }
503	                    }
504	                    Some(extra) => {
505	                        let ack_seq = packet.ack_seq_number().unwrap();
506	                        let send_ack2 = {
507	                            let state = self.state();
508	                            state.last_ack2_time.elapsed() > SYN_INTERVAL
509	                                || ack_seq == state.last_ack2_sent_back
510	                        };
511	                        if send_ack2 {
512	                            if let Some(peer) = self.peer_socket_id() {
513	                                let ack2_packet = UdtControlPacket::new_ack2(ack_seq, peer);
514	                                self.send_packet(ack2_packet.into()).await?;
515	                                let mut state = self.state();
516	                                state.last_ack2_sent_back = ack_seq;
517	                                state.last_ack2_time = Instant::now();
518	                            }
519	                        }
520	
521	                        let seq = ack.next_seq_number;
522	
523	                        {
524	                            let mut state = self.state();
525	                            if (seq - state.curr_snd_seq_number) > 1 {
526	                                // This should not happen
527	                                if *UDT_DEBUG {
528	                                    eprintln!(
529	                                        "Udt socket broken: seq number is larger than expected"
530	                                    );
531	                                };
532	                                *self.status.lock().unwrap() = UdtStatus::Broken;
533	                            }
534	
535	                            if (seq - state.last_ack_received) >= 0 {
536	                                self.flow.write().unwrap().flow_window_size =
537	                                    extra.available_buf_size;
538	                                state.last_ack_received = seq;
539	                            }
540	
541	                            let offset = seq - state.last_data_ack_processed;
542	                            if offset <= 0 {
543	                                // Ignore repeated acks
544	                                return Ok(());
545	                            }
546	
547	                            self.snd_buffer.lock().unwrap().ack_data(offset);
548	                            let last_data_ack_processed = state.last_data_ack_processed;
549	                            state
550	                                .snd_loss_list
551	                                .remove_all(last_data_ack_processed, seq - 1);
552	                            // TODO record times for monitoring purposes
553	                            state.last_data_ack_processed = seq;
554	                            self.update_snd_queue(false);
555	                            self.ack_notify.notify_waiters();
556	                        }
557	
558	                        let mut flow = self.flow.write().unwrap();
559	                        flow.update_rtt(Duration::from_micros(extra.rtt.into()));
560	                        flow.update_rtt_var(Duration::from_micros(extra.rtt_variance.into()));
561	
562	                        {
563	                            let mut rate_control = self.rate_control.write().unwrap();
564	                            rate_control.set_rtt(flow.rtt);
565	
566	                            if extra.pack_recv_rate > 0 {
567	                                flow.update_peer_delivery_rate(extra.pack_recv_rate);
568	                                rate_control.set_rcv_rate(flow.peer_delivery_rate);
569	                            }
570	                            if extra.link_capacity > 0 {
571	                                flow.update_bandwidth(extra.link_capacity);
572	                                rate_control.set_bandwidth(flow.peer_bandwidth);
573	                            }
574	
575	                            rate_control.on_ack(seq);
576	                        }
577	                        self.cc_update();
578	                    }
579	                }
580	            }
581	            ControlPacketType::Ack2 => {
582	                let ack_seq = packet.ack_seq_number().unwrap();
583	                let window = self.state().ack_window.get(ack_seq);
584	                if let Some((seq, rtt)) = window {
585	                    let mut flow = self.flow.write().unwrap();
586	                    let rtt_abs_diff = {
587	                        if rtt > flow.rtt {
588	                            rtt - flow.rtt
589	                        } else {
590	                            flow.rtt - rtt
591	                        }
592	                    };
593	                    flow.update_rtt_var(rtt_abs_diff);
594	                    flow.update_rtt(rtt);
595	                    drop(flow);
596	                    let mut state = self.state();
597	                    if (seq - state.last_ack2_received) > 0 {
598	                        state.last_ack2_received = seq;
599	                    }
600	                }
601	            }
602	            ControlPacketType::Nak(ref nak) => {
603	                let mut broken = false;
604	                {
605	                    let mut rate_control = self.rate_control.write().unwrap();
606	                    if nak.loss_info.is_empty() {
607	                        if *UDT_DEBUG {
608	                            eprintln!("Received NAK with empty list");
609	                        }
610	                        return Ok(());
611	                    }
612	                    rate_control.on_loss((nak.loss_info[0] & 0x7fff_ffff).into());
613	                }
614	                self.cc_update();
615	
616	                let loss_iter = &mut nak.loss_info.iter();
617	                let mut state = self.state();
618	                while let Some(loss) = loss_iter.next() {
619	                    let (seq_start, seq_end) = {
620	                        if loss & 0x8000_0000 != 0 {
621	                            if let Some(seq_end) = loss_iter.next() {
622	                                let seq_start: SeqNumber = (loss & 0x7fff_ffff).into();
623	                                let seq_end: SeqNumber = (*seq_end).into();
624	                                (seq_start, seq_end)
625	                            } else {
626	                                broken = true;
627	                                break;
628	                            }
629	                        } else {
630	                            ((*loss).into(), (*loss).into())
631	                        }
632	                    };
633	                    if (seq_start - seq_end > 0) || (seq_end - state.curr_snd_seq_number > 0) {
634	                        broken = true;
635	                        break;
636	                    }
637	                    if seq_start - state.last_ack_received >= 0 {
638	                        state.snd_loss_list.insert(seq_start, seq_end);
639	                    } else if seq_end - state.last_ack_received >= 0 {
640	                        let last_ack_received = state.last_ack_received;
641	                        state.snd_loss_list.insert(last_ack_received, seq_end);
642	                    }
643	                }
644	
645	                if broken {
646	                    println!("NAK is broken: {:?} {:?}", nak, state);
647	                    *self.status.lock().unwrap() = UdtStatus::Broken;
648	                    return Ok(());
649	                }
650	
651	                self.update_snd_queue(true);
652	            }
653	            ControlPacketType::Shutdown => {
654	                *self.status.lock().unwrap() = UdtStatus::Closing;
655	                self.notify_all();
656	            }
657	            ControlPacketType::MsgDropRequest(ref drop) => {
658	                let msg_number = packet.msg_seq_number().unwrap();
659	                self.rcv_buffer.lock().unwrap().drop_msg(msg_number);
660	                let mut state = self.state();
661	                state
662	                    .rcv_loss_list
663	                    .remove_all(drop.first_seq_number, drop.last_seq_number);
664	                if (drop.first_seq_number - (state.curr_rcv_seq_number + 1)) <= 0
665	                    && (drop.last_seq_number - state.curr_rcv_seq_number) > 0
666	                {
667	                    state.curr_rcv_seq_number = drop.last_seq_number;
668	                }
669	            }
670	            ControlPacketType::UserDefined => unimplemented!(),
671	        }
672	        Ok(())
673	    }
