784	    async fn send_ack(&self, light: bool) -> Result<()> {
785	        let seq_number = {
786	            let state = self.state();
787	            let seq_number = match state
788	                .rcv_loss_list
789	                .peek_after(state.curr_rcv_seq_number + 1)
790	            {
791	                Some(num) => num,
792	                None => state.curr_rcv_seq_number + 1,
793	            };
794	            if seq_number == state.last_ack2_received {
795	                return Ok(());
796	            }
797	            seq_number
798	        };
799	
800	        if light {
801	            // Save time on buffer procesing and bandwith measurement
802	            let ack_packet = UdtControlPacket::new_ack(
803	                0.into(),
804	                seq_number,
805	                self.peer_socket_id().unwrap(),
806	                None,
807	            );
808	            self.send_packet(ack_packet.into()).await?;
809	            return Ok(());
810	        }
811	
812	        {
813	            let mut state = self.state();
814	            let to_ack: i32 = seq_number - state.last_sent_ack;
815	            match to_ack.cmp(&0) {
816	                Ordering::Greater => {
817	                    self.rcv_buffer().ack_data(seq_number);
818	                    state.last_sent_ack = seq_number;
819	                    self.rcv_notify.notify_waiters();
820	                }
821	                Ordering::Equal => {
822	                    let last_sent_ack_elapsed = state.last_sent_ack_time.elapsed();
823	                    drop(state);
824	                    let flow = self.flow.read().unwrap();
825	                    if last_sent_ack_elapsed < (flow.rtt + 4 * flow.rtt_var) {
826	                        return Ok(());
827	                    }
828	                }
829	                _ => {
830	                    return Ok(());
831	                }
832	            }
833	        }
834	
835	        let ack_packet = {
836	            let mut state = self.state();
837	            if (state.last_sent_ack - state.last_ack2_received) > 0 {
838	                state.last_ack_seq_number = state.last_ack_seq_number + 1;
839	                drop(state);
840	                let mut ack_info = {
841	                    let flow = self.flow.read().unwrap();
842	                    AckOptionalInfo {
843	                        rtt: flow.rtt.as_micros().try_into().unwrap_or(u32::MAX),
844	                        rtt_variance: flow.rtt_var.as_micros().try_into().unwrap_or(u32::MAX),
845	                        available_buf_size: std::cmp::max(
846	                            self.rcv_buffer().get_available_buf_size(),
847	                            2,
848	                        ),
849	                        pack_recv_rate: 0,
850	                        link_capacity: 0,
851	                    }
852	                };
853	                if self.state().last_sent_ack_time.elapsed() > SYN_INTERVAL {
854	                    let flow = self.flow.read().unwrap();
855	                    ack_info.pack_recv_rate = flow.get_pkt_rcv_speed();
856	                    ack_info.link_capacity = flow.get_bandwidth();
857	                    self.state().last_sent_ack_time = Instant::now();
858	                }
859	                let state = self.state();
860	                Some(UdtControlPacket::new_ack(
861	                    state.last_ack_seq_number,
862	                    state.last_sent_ack,
863	                    self.peer_socket_id().unwrap(),
864	                    Some(ack_info),
865	                ))
866	            } else {
867	                None
868	            }
869	        };
870	
871	        if let Some(ack_packet) = ack_packet {
872	            self.send_packet(ack_packet.into()).await?;
873	            let mut state = self.state();
874	            let last_sent_ack = state.last_sent_ack;
875	            let last_ack_seq_number = state.last_ack_seq_number;
876	            state.ack_window.store(last_sent_ack, last_ack_seq_number);
877	        }
878	
879	        Ok(())
880	    }
