887	    pub(crate) async fn check_timers(&self) {
888	        self.cc_update();
889	        let now = Instant::now();
890	
891	        let ack_interval = self.rate_control.read().unwrap().get_ack_pkt_interval();
892	        if now > self.state().next_ack_time
893	            || (ack_interval > 0 && ack_interval <= self.state().pkt_count)
894	        {
895	            self.send_ack(false).await.unwrap_or_else(|err| {
896	                if *UDT_DEBUG {
897	                    eprintln!("failed to send ack: {:?}", err);
898	                }
899	            });
900	            let ack_period = self.rate_control.read().unwrap().get_ack_period();
901	            let mut state = self.state();
902	            state.next_ack_time = now + ack_period;
903	            state.pkt_count = 0;
904	            state.light_ack_counter = 0;
905	        } else {
906	            let send_light_ack = {
907	                let state = self.state();
908	                (state.light_ack_counter + 1) * PACKETS_BETWEEN_LIGHT_ACK <= state.pkt_count
909	            };
910	            if send_light_ack {
911	                self.send_ack(true).await.unwrap_or_else(|err| {
912	                    if *UDT_DEBUG {
913	                        eprintln!("failed to send ack: {:?}", err);
914	                    }
915	                });
916	                self.state().light_ack_counter += 1;
917	            }
918	        }
919	
920	        let next_exp_time = {
921	            let (rtt, rtt_var) = {
922	                let flow = self.flow.read().unwrap();
923	                (flow.rtt, flow.rtt_var)
924	            };
925	            let state = self.state();
926	            let exp_int = state.exp_count * (rtt + 4 * rtt_var) + SYN_INTERVAL;
927	            let next_exp = std::cmp::max(exp_int, state.exp_count * MIN_EXP_INTERVAL);
928	            state.last_rsp_time + next_exp
929	        };
930	        if now > next_exp_time {
931	            {
932	                let state = self.state();
933	                if state.exp_count > 16 && state.last_rsp_time.elapsed() > Duration::from_secs(5) {
934	                    // Connection is broken
935	                    *self.status.lock().unwrap() = UdtStatus::Broken;
936	                    self.update_snd_queue(true);
937	                    return;
938	                }
939	            }
940	
941	            if self.snd_buffer.lock().unwrap().is_empty() {
942	                if let Some(peer_socket_id) = self.peer_socket_id() {
943	                    let keep_alive = UdtControlPacket::new_keep_alive(peer_socket_id);
944	                    self.send_packet(keep_alive.into())
945	                        .await
946	                        .unwrap_or_else(|err| {
947	                            if *UDT_DEBUG {
948	                                eprintln!("failed to send keep alive: {:?}", err);
949	                            };
950	                        });
951	                }
952	            } else {
953	                {
954	                    let mut state = self.state();
955	                    if (state.last_ack_received != state.curr_snd_seq_number + 1)
956	                        && state.snd_loss_list.is_empty()
957	                    {
958	                        let last_ack_received = state.last_ack_received;
959	                        let curr_snd_seq_number = state.curr_snd_seq_number;
960	                        state
961	                            .snd_loss_list
962	                            .insert(last_ack_received, curr_snd_seq_number);
963	                    }
964	                }
965	
966	                self.rate_control.write().unwrap().on_timeout();
967	                self.cc_update();
968	                self.update_snd_queue(true);
969	            }
970	
971	            let mut state = self.state();
972	            state.exp_count += 1;
973	            // Reset last response time since we just sent a heart-beat.
974	            state.last_rsp_time = now;
975	        }
976	    }
