1153	    pub async fn close(&self) {
1154	        let status = self.status();
1155	        if status == UdtStatus::Closed || status == UdtStatus::Closing {
1156	            return;
1157	        }
1158	        let now = Instant::now();
1159	        let linger_timeout = self
1160	            .configuration
1161	            .read()
1162	            .unwrap()
1163	            .linger_timeout
1164	            .unwrap_or(Duration::ZERO);
1165	
1166	        while self.status() == UdtStatus::Connected
1167	            && !self.snd_buffer_is_empty()
1168	            && now.elapsed() < linger_timeout
1169	        {
1170	            self.wait_for_next_ack_or_empty_snd_buffer().await;
1171	        }
1172	
1173	        if let Some(mux) = self.multiplexer() {
1174	            mux.snd_queue.remove(self.socket_id);
1175	            let listener_id = mux.listener.read().await.clone().map(|s| s.socket_id);
1176	            if listener_id == Some(self.socket_id) {
1177	                *mux.listener.write().await = None;
1178	            }
1179	        }
1180	
1181	        // TODO: remove socket from rendezvous queue
1182	
1183	        if self.status() == UdtStatus::Connected {
1184	            let shutdown = UdtControlPacket::new_shutdown(self.peer_socket_id().unwrap());
1185	            self.send_packet(shutdown.into())
1186	                .await
1187	                .unwrap_or_else(|err| {
1188	                    if *UDT_DEBUG {
1189	                        eprintln!("Failed to send shutdown packet: {}", err);
1190	                    }
1191	                });
1192	        }
1193	
1194	        // TODO: keep channel stats (RTT, bandwidth, etc.) in a cache for more efficient reconnections.
1195	        *self.status.lock().unwrap() = UdtStatus::Closing;
1196	        self.notify_all();
1197	    }
